//! Causal Data Unit (CDU): the unified, encrypted, verifiable atom of knowledge.

use cdqn_cryptocore::hash_sha3_256;
use cdqn_hlc::{HlcTimestamp, HybridLogicalClock};

/// The immutable core content of a CDU.
#[derive(Debug, Clone)]
pub struct Payload {
    pub data: Vec<u8>,
    pub payload_type: String,
}

impl Payload {
    #[must_use]
    pub fn hash(&self) -> [u8; 32] {
        let mut canonical = self.payload_type.as_bytes().to_vec();
        canonical.extend_from_slice(&self.data);
        hash_sha3_256(&canonical)
    }
}

/// The mutable context around the payload.
#[derive(Debug, Clone)]
pub struct Metadata {
    pub author_node: Vec<u8>,
    pub context_refs: Vec<Vec<u8>>,
    pub state: String,
    pub weight: f64,
    pub r_coordinate: f64,
    pub world_context: String,
    pub hlc_timestamp: HlcTimestamp,
}

/// A signature entry in the append-only log.
#[derive(Debug, Clone)]
pub struct Signature {
    pub signer_entity: String,
    pub timestamp: HlcTimestamp,
    pub signature: Vec<u8>,
}

/// The complete Causal Data Unit.
#[derive(Debug, Clone)]
pub struct Cdu {
    pub id_hlc: Vec<u8>,
    pub payload: Payload,
    pub payload_hash: [u8; 32],
    pub metadata: Metadata,
    pub signatures: Vec<Signature>,
}

impl Cdu {
    #[must_use]
    pub fn new(
        payload: Payload,
        mut metadata: Metadata,
        hlc: &HybridLogicalClock,
        node_id: &[u8],
    ) -> Self {
        let payload_hash = payload.hash();
        let hlc_ts = hlc.new_timestamp();
        metadata.hlc_timestamp = hlc_ts;

        let mut id_input = hlc_ts.as_u64().to_be_bytes().to_vec();
        id_input.extend_from_slice(node_id);
        id_input.extend_from_slice(&payload_hash);

        let id_hlc = hash_sha3_256(&id_input).to_vec();

        Self {
            id_hlc,
            payload_hash,
            payload,
            metadata,
            signatures: Vec::new(),
        }
    }

    #[must_use]
    pub fn with_signature(mut self, signature: Signature) -> Self {
        self.signatures.push(signature);
        self
    }
}

